using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    // Get active design
    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    Ptr sheetMetalRules = design->librarySheetMetalRules();
    if (!sheetMetalRules->item(0))
        return false;

    // Get the first sheet metal rule, it should be named "Steel (mm)" and should be in the library by default.
    Ptr steelRule = sheetMetalRules->item(0);
    if (!steelRule)
        return false;

    // Create a rule by copying the "Steel (mm)" rule.
    Ptr steelRuleCopy = sheetMetalRules->addByCopy(steelRule, "Steel Two (mm)");
    if (!steelRuleCopy)
        return false;

    // Some properties can be changed directly.

    // Others need to be changed by value.
    Ptr thicknessValue = steelRuleCopy->thickness();
    Ptr gapValue = steelRuleCopy->gap();

    // Example of creating a third rule, then deleting it.
    Ptr ruleToDelete = sheetMetalRules->addByCopy(steelRuleCopy, "Steel Three (mm)");

    return true;
}
